import { useCallback, useEffect, useSyncExternalStore } from "react";
import {
  BUILTIN_THEMES,
  isThemeId,
  type ThemeColors,
  type ThemeDefinition,
  type ThemeId,
} from "@t3tools/shared/theme";

// ---------------------------------------------------------------------------
// Public types
// ---------------------------------------------------------------------------

/** Persisted theme selection: a specific theme ID or auto-detect from OS. */
export type ThemeSelection = ThemeId | "system";

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------

const STORAGE_KEY = "t3code:theme";
const MEDIA_QUERY = "(prefers-color-scheme: dark)";

/**
 * Maps each ThemeColors key to the CSS custom property set on `<html>`.
 *
 * Core properties (--background, --foreground, --primary, --primary-foreground)
 * override the existing design-token layer so derived tokens (--card, --popover,
 * --muted, etc.) cascade correctly through the existing CSS rules.
 *
 * Area-specific properties (--sidebar, --editor, --terminal, --statusbar) are
 * new additions registered in the Tailwind `@theme inline` block.
 */
const COLOR_TO_CSS_PROP: Readonly<Record<keyof ThemeColors, string>> = {
  background: "--background",
  foreground: "--foreground",
  accent: "--primary",
  accentForeground: "--primary-foreground",
  sidebar: "--sidebar",
  sidebarForeground: "--sidebar-foreground",
  editor: "--editor",
  editorForeground: "--editor-foreground",
  terminal: "--terminal",
  terminalForeground: "--terminal-foreground",
  statusBar: "--statusbar",
  statusBarForeground: "--statusbar-foreground",
};

// ---------------------------------------------------------------------------
// External store (shared across all hook instances)
// ---------------------------------------------------------------------------

type ThemeSnapshot = {
  selection: ThemeSelection;
  systemDark: boolean;
};

let listeners: Array<() => void> = [];
let lastSnapshot: ThemeSnapshot | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

function getSystemDark(): boolean {
  return window.matchMedia(MEDIA_QUERY).matches;
}

function getStored(): ThemeSelection {
  const raw = localStorage.getItem(STORAGE_KEY);
  if (raw === "system") return "system";
  if (raw != null && isThemeId(raw)) return raw;
  // Migrate legacy "light" / "dark" values from the old hook
  if (raw === "light") return "t3-light";
  if (raw === "dark") return "t3-dark";
  return "system";
}

/** Resolve a ThemeSelection to a concrete ThemeDefinition. */
function resolveTheme(selection: ThemeSelection): ThemeDefinition {
  if (selection === "system") {
    return BUILTIN_THEMES[getSystemDark() ? "t3-dark" : "t3-light"];
  }
  return BUILTIN_THEMES[selection];
}

// ---------------------------------------------------------------------------
// DOM side-effects
// ---------------------------------------------------------------------------

function applyTheme(selection: ThemeSelection, suppressTransitions = false) {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  const definition = resolveTheme(selection);

  // Toggle .dark class for third-party library compat (syntax highlighters, etc.)
  document.documentElement.classList.toggle("dark", definition.base === "dark");

  // Apply every theme color as a CSS custom property (inline style on <html>).
  // Inline styles override the `:root` / `@variant dark` defaults in index.css.
  const style = document.documentElement.style;
  for (const key of Object.keys(COLOR_TO_CSS_PROP) as Array<keyof ThemeColors>) {
    style.setProperty(COLOR_TO_CSS_PROP[key], definition.colors[key]);
  }
  // Keep --ring in sync with the accent/primary color for focus rings.
  style.setProperty("--ring", definition.colors.accent);

  // Expose theme id as a data attribute for potential CSS selectors
  document.documentElement.dataset.theme = definition.id;

  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash
applyTheme(getStored());

// ---------------------------------------------------------------------------
// Snapshot for useSyncExternalStore
// ---------------------------------------------------------------------------

function getSnapshot(): ThemeSnapshot {
  const selection = getStored();
  const systemDark = selection === "system" ? getSystemDark() : false;

  if (
    lastSnapshot &&
    lastSnapshot.selection === selection &&
    lastSnapshot.systemDark === systemDark
  ) {
    return lastSnapshot;
  }

  lastSnapshot = { selection, systemDark };
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Listen for system preference changes
  const mq = window.matchMedia(MEDIA_QUERY);
  const handleChange = () => {
    if (getStored() === "system") applyTheme("system", true);
    emitChange();
  };
  mq.addEventListener("change", handleChange);

  // Listen for storage changes from other tabs
  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      applyTheme(getStored(), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    mq.removeEventListener("change", handleChange);
    window.removeEventListener("storage", handleStorage);
  };
}

// ---------------------------------------------------------------------------
// React hook
// ---------------------------------------------------------------------------

export function useTheme() {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);

  const definition = resolveTheme(snapshot.selection);
  const resolvedTheme: "light" | "dark" = definition.base;

  const setTheme = useCallback((next: ThemeSelection) => {
    localStorage.setItem(STORAGE_KEY, next);
    applyTheme(next, true);
    emitChange();
  }, []);

  // Keep DOM in sync on mount/change
  useEffect(() => {
    applyTheme(snapshot.selection);
  }, [snapshot.selection]);

  return {
    /** The raw selection: a ThemeId or "system". */
    theme: snapshot.selection,
    /** Update the persisted theme selection. */
    setTheme,
    /** Resolved base mode for library compat (always "light" or "dark"). */
    resolvedTheme,
    /** The fully resolved ThemeDefinition currently in effect. */
    themeDefinition: definition,
  } as const;
}

