import type { ThemeDefinition } from "@t3tools/shared/theme";
import { BUILTIN_THEME_LIST } from "@t3tools/shared/theme";
import { useTheme } from "~/hooks/useTheme";

// ---------------------------------------------------------------------------
// Swatch components
// ---------------------------------------------------------------------------

/** Small color swatch that previews a theme's key colors in a mini-IDE layout. */
function ThemeSwatch({ theme }: { theme: ThemeDefinition }) {
  return (
    <div
      className="flex h-16 w-full overflow-hidden rounded-md border border-border"
      style={{ backgroundColor: theme.colors.background }}
    >
      {/* Sidebar slice */}
      <div
        className="flex h-full w-5 flex-col items-center justify-end pb-1"
        style={{ backgroundColor: theme.colors.sidebar }}
      >
        <div
          className="h-1 w-2.5 rounded-sm"
          style={{ backgroundColor: theme.colors.sidebarForeground, opacity: 0.5 }}
        />
        <div
          className="mt-0.5 h-1 w-2.5 rounded-sm"
          style={{ backgroundColor: theme.colors.sidebarForeground, opacity: 0.3 }}
        />
      </div>

      {/* Main area */}
      <div className="flex flex-1 flex-col">
        {/* Editor area */}
        <div
          className="flex flex-1 items-center px-1.5 pt-1.5"
          style={{ backgroundColor: theme.colors.editor }}
        >
          <div className="flex flex-col gap-0.5">
            <div
              className="h-1 w-10 rounded-sm"
              style={{ backgroundColor: theme.colors.editorForeground, opacity: 0.5 }}
            />
            <div
              className="h-1 w-7 rounded-sm"
              style={{ backgroundColor: theme.colors.accent, opacity: 0.7 }}
            />
            <div
              className="h-1 w-8 rounded-sm"
              style={{ backgroundColor: theme.colors.editorForeground, opacity: 0.3 }}
            />
          </div>
        </div>

        {/* Terminal strip */}
        <div
          className="flex h-3 items-center px-1.5"
          style={{ backgroundColor: theme.colors.terminal }}
        >
          <div
            className="h-0.5 w-5 rounded-sm"
            style={{ backgroundColor: theme.colors.terminalForeground, opacity: 0.4 }}
          />
        </div>

        {/* Status bar */}
        <div
          className="flex h-2.5 items-center px-1.5"
          style={{ backgroundColor: theme.colors.statusBar }}
        >
          <div
            className="h-0.5 w-4 rounded-sm"
            style={{ backgroundColor: theme.colors.statusBarForeground, opacity: 0.5 }}
          />
        </div>
      </div>
    </div>
  );
}

/** System theme preview showing light and dark swatches side-by-side. */
function SystemSwatch() {
  const light = BUILTIN_THEME_LIST[0]!;
  const dark = BUILTIN_THEME_LIST[1]!;

  return (
    <div className="flex h-16 w-full gap-px overflow-hidden rounded-md border border-border">
      <div className="flex-1" style={{ backgroundColor: light.colors.background }}>
        <div className="flex h-full">
          <div className="w-3" style={{ backgroundColor: light.colors.sidebar }} />
          <div className="flex flex-1 flex-col justify-center px-1.5">
            <div
              className="h-1 w-8 rounded-sm"
              style={{ backgroundColor: light.colors.foreground, opacity: 0.4 }}
            />
            <div
              className="mt-0.5 h-1 w-5 rounded-sm"
              style={{ backgroundColor: light.colors.accent, opacity: 0.6 }}
            />
          </div>
        </div>
      </div>
      <div className="flex-1" style={{ backgroundColor: dark.colors.background }}>
        <div className="flex h-full">
          <div className="w-3" style={{ backgroundColor: dark.colors.sidebar }} />
          <div className="flex flex-1 flex-col justify-center px-1.5">
            <div
              className="h-1 w-8 rounded-sm"
              style={{ backgroundColor: dark.colors.foreground, opacity: 0.4 }}
            />
            <div
              className="mt-0.5 h-1 w-5 rounded-sm"
              style={{ backgroundColor: dark.colors.accent, opacity: 0.6 }}
            />
          </div>
        </div>
      </div>
    </div>
  );
}

// ---------------------------------------------------------------------------
// Option card
// ---------------------------------------------------------------------------

function ThemeOptionCard({
  selected,
  label,
  description,
  onClick,
  children,
}: {
  selected: boolean;
  label: string;
  description: string;
  onClick: () => void;
  children: React.ReactNode;
}) {
  return (
    <button
      type="button"
      role="radio"
      aria-checked={selected}
      className={`flex w-full flex-col gap-2 rounded-lg border p-3 text-left transition-colors ${
        selected
          ? "border-primary/60 bg-primary/8 text-foreground"
          : "border-border bg-background text-muted-foreground hover:bg-accent"
      }`}
      onClick={onClick}
    >
      {children}
      <div className="flex items-center justify-between gap-2">
        <span className="flex flex-col">
          <span className="text-sm font-medium">{label}</span>
          <span className="text-xs">{description}</span>
        </span>
        {selected ? (
          <span className="shrink-0 rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
            Active
          </span>
        ) : null}
      </div>
    </button>
  );
}

// ---------------------------------------------------------------------------
// Exported component
// ---------------------------------------------------------------------------

/** Theme selector with preview swatches for the settings page. */
export function ThemeSelector() {
  const { theme, setTheme, themeDefinition } = useTheme();

  return (
    <section className="rounded-2xl border border-border bg-card p-5">
      <div className="mb-4">
        <h2 className="text-sm font-medium text-foreground">Appearance</h2>
        <p className="mt-1 text-xs text-muted-foreground">Choose a color theme for T3 Code.</p>
      </div>

      <div className="grid gap-3 sm:grid-cols-2" role="radiogroup" aria-label="Theme preference">
        {/* System auto-detect option */}
        <ThemeOptionCard
          selected={theme === "system"}
          label="System"
          description="Match your OS appearance."
          onClick={() => setTheme("system")}
        >
          <SystemSwatch />
        </ThemeOptionCard>

        {/* Built-in themes */}
        {BUILTIN_THEME_LIST.map((def) => (
          <ThemeOptionCard
            key={def.id}
            selected={theme === def.id}
            label={def.name}
            description={`${def.base === "dark" ? "Dark" : "Light"} theme.`}
            onClick={() => setTheme(def.id)}
          >
            <ThemeSwatch theme={def} />
          </ThemeOptionCard>
        ))}
      </div>

      <p className="mt-4 text-xs text-muted-foreground">
        Active theme:{" "}
        <span className="font-medium text-foreground">{themeDefinition.name}</span>
        {theme === "system" ? " (system)" : ""}
      </p>
    </section>
  );
}

