              style={{ backgroundColor: dark.colors.accent, opacity: 0.6 }}
            />
          </div>
        </div>
      </div>
    </div>
  );
}

// ---------------------------------------------------------------------------
// Option card
// ---------------------------------------------------------------------------

function ThemeOptionCard({
  selected,
  label,
  description,
  onClick,
  children,
}: {
  selected: boolean;
  label: string;
  description: string;
  onClick: () => void;
  children: React.ReactNode;
}) {
  return (
    <button
      type="button"
      role="radio"
      aria-checked={selected}
      className={`flex w-full flex-col gap-2 rounded-lg border p-3 text-left transition-colors ${
        selected
          ? "border-primary/60 bg-primary/8 text-foreground"
          : "border-border bg-background text-muted-foreground hover:bg-accent"
      }`}
      onClick={onClick}
    >
      {children}
      <div className="flex items-center justify-between gap-2">
        <span className="flex flex-col">
          <span className="text-sm font-medium">{label}</span>
          <span className="text-xs">{description}</span>
        </span>
        {selected ? (
          <span className="shrink-0 rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
            Active
          </span>
        ) : null}
      </div>
    </button>
  );
}

// ---------------------------------------------------------------------------
// Exported component
// ---------------------------------------------------------------------------

/** Theme selector with preview swatches for the settings page. */
export function ThemeSelector() {
  const { theme, setTheme, themeDefinition } = useTheme();

  return (
    <section className="rounded-2xl border border-border bg-card p-5">
      <div className="mb-4">
        <h2 className="text-sm font-medium text-foreground">Appearance</h2>
        <p className="mt-1 text-xs text-muted-foreground">Choose a color theme for T3 Code.</p>
      </div>

      <div className="grid gap-3 sm:grid-cols-2" role="radiogroup" aria-label="Theme preference">
        {/* System auto-detect option */}
        <ThemeOptionCard
          selected={theme === "system"}
          label="System"
          description="Match your OS appearance."
          onClick={() => setTheme("system")}
        >
          <SystemSwatch />
        </ThemeOptionCard>

        {/* Built-in themes */}
        {BUILTIN_THEME_LIST.map((def) => (
          <ThemeOptionCard
            key={def.id}
            selected={theme === def.id}
            label={def.name}
            description={`${def.base === "dark" ? "Dark" : "Light"} theme.`}
            onClick={() => setTheme(def.id)}
          >
            <ThemeSwatch theme={def} />
          </ThemeOptionCard>
        ))}
      </div>

      <p className="mt-4 text-xs text-muted-foreground">
        Active theme:{" "}
        <span className="font-medium text-foreground">{themeDefinition.name}</span>
        {theme === "system" ? " (system)" : ""}
      </p>
    </section>
  );
}

